// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MyNFT is ERC721Enumerable, Ownable, ReentrancyGuard {
    uint256 public constant MAX_SUPPLY = 10000;
    uint256 public constant MINT_PRICE = 0.08 ether;
    uint256 public constant PRE_SALE_LIMIT = 500;
    uint256 public totalSupply;
    string public baseURI;
    mapping(address => bool) public whitelist;
    bool public presaleActive;
    bool public publicSaleActive;
    bool public presaleTimeWindowActive;
    uint256 public presaleStartTime;
    uint256 public presaleEndTime;
    mapping(uint256 => bool) private redeemed;

    enum SaleState { NotActive, PresaleActive, PublicSaleActive }
    SaleState public currentSaleState = SaleState.NotActive;

    event Redeemed(address indexed redeemer, uint256 tokenId);

    constructor(string memory _baseURI) ERC721("MyNFT", "MNFT") {
        baseURI = _baseURI;
    }

    modifier onlyOneSaleStateActive() {
        require(currentSaleState == SaleState.NotActive, "Only one sale state can be active at a time");
        _;
    }

    modifier presaleActive() {
        require(currentSaleState == SaleState.PresaleActive, "Presale is not active");
        require(block.timestamp >= presaleStartTime && block.timestamp <= presaleEndTime, "Presale time window is not active");
        require(whitelist[msg.sender], "Sender is not whitelisted");
        require(totalSupply + 1 <= PRE_SALE_LIMIT, "Presale limit reached");
        _;
    }

    modifier publicSaleActive() {
        require(currentSaleState == SaleState.PublicSaleActive, "Public sale is not active");
        require(totalSupply + 1 <= MAX_SUPPLY, "Exceeds max supply");
        _;
    }

    function whitelistAddresses(address[] calldata addresses) external onlyOwner {
        for (uint256 i = 0; i < addresses.length; i++) {
            whitelist[addresses[i]] = true;
        }
    }

    function setPresaleInfo(bool isActive, uint256 startTime, uint256 endTime) external onlyOwner onlyOneSaleStateActive {
        presaleActive = isActive;
        presaleStartTime = startTime;
        presaleEndTime = endTime;
        if (isActive) {
            currentSaleState = SaleState.PresaleActive;
        } else {
            currentSaleState = SaleState.NotActive;
        }
    }

    function setPublicSaleActive(bool isActive) external onlyOwner onlyOneSaleStateActive {
        publicSaleActive = isActive;
        if (isActive) {
            currentSaleState = SaleState.PublicSaleActive;
        } else {
            currentSaleState = SaleState.NotActive;
        }
    }

    function preSaleMint() external payable presaleActive {
        require(msg.value >= MINT_PRICE, "Insufficient payment");
        totalSupply++;
        _safeMint(msg.sender, totalSupply);
    }

    function mint() external payable publicSaleActive {
        require(msg.value >= MINT_PRICE, "Insufficient payment");
        totalSupply++;
        _safeMint(msg.sender, totalSupply);
    }

    function redeemBook(uint256 tokenId) external {
        require(_isApprovedOrOwner(msg.sender, tokenId), "Caller is not owner nor approved");
        require(redeemed[tokenId] == false, "Token already redeemed");

        redeemed[tokenId] = true;
        emit Redeemed(msg.sender, tokenId);
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseURI;
    }

    function withdraw() external onlyOwner nonReentrant {
        payable(owner()).transfer(address(this).balance);
    }
}
