    function mint() external payable {
        require(publicSaleActive, "Public sale is not active");
        require(totalSupply + 1 <= MAX_SUPPLY, "Exceeds max supply");

        totalSupply++;
        _safeMint(msg.sender, totalSupply);
    }

    function redeemBook(uint256 tokenId) external {
        require(_isApprovedOrOwner(msg.sender, tokenId), "Caller is not owner nor approved");
        require(redeemed[tokenId] == false, "Token already redeemed");

        redeemed[tokenId] = true;
        emit Redeemed(msg.sender, tokenId);
    }

    function setSaleState(bool _presaleActive, bool _publicSaleActive) external onlyOwner {
        presaleActive = _presaleActive;
        publicSaleActive = _publicSaleActive;
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseURI;
    }

    function withdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    mapping(uint256 => bool) private redeemed;
}
