        require(totalSupply + 1 <= PRE_SALE_LIMIT, "Presale limit reached");
        _;
    }

    modifier publicSaleActive() {
        require(currentSaleState == SaleState.PublicSaleActive, "Public sale is not active");
        require(totalSupply + 1 <= MAX_SUPPLY, "Exceeds max supply");
        _;
    }

    function whitelistAddresses(address[] calldata addresses) external onlyOwner {
        for (uint256 i = 0; i < addresses.length; i++) {
            whitelist[addresses[i]] = true;
        }
    }

    function setPresaleInfo(bool isActive, uint256 startTime, uint256 endTime) external onlyOwner onlyOneSaleStateActive {
        presaleActive = isActive;
        presaleStartTime = startTime;
        presaleEndTime = endTime;
        if (isActive) {
            currentSaleState = SaleState.PresaleActive;
        } else {
            currentSaleState = SaleState.NotActive;
        }
    }

    function setPublicSaleActive(bool isActive) external onlyOwner onlyOneSaleStateActive {
        publicSaleActive = isActive;
        if (isActive) {
            currentSaleState = SaleState.PublicSaleActive;
        } else {
            currentSaleState = SaleState.NotActive;
        }
    }

    function preSaleMint() external payable presaleActive {
        totalSupply++;
        _safeMint(msg.sender, totalSupply);
    }

    function mint() external payable publicSaleActive {
        totalSupply++;
        _safeMint(msg.sender, totalSupply);
    }

    function redeemBook(uint256 tokenId) external {
        require(_isApprovedOrOwner(msg.sender, tokenId), "Caller is not owner nor approved");
        require(redeemed[tokenId] == false, "Token already redeemed");

        redeemed[tokenId] = true;
        emit Redeemed(msg.sender, tokenId);
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseURI;
    }

    function withdraw() external onlyOwner nonReentrant {
        payable(owner()).transfer(address(this).balance);
    }
}
